import vex
from typing import List, Dict, Any

@vex.verify(
    checks=[
        vex.completeness(required_fields=["invoice_number", "total_amount", "line_items"]),
        vex.type_consistency(),
        vex.custom(lambda x: len(x.get('line_items', [])) > 0, "Has line items")
    ]
)
def safe_extraction(document: str) -> Dict[str, Any]:
    agent = Agent(model="gpt-4o")
    return agent.run(document)

verified_result = safe_extraction("Multi-page invoice document...")

import vex
from agno.agents import Team

@vex.verify(
    checks=[
        vex.semantic_consistency(fields=["total_amount"]),
        vex.numerical_accuracy(tolerance=0.01),
        vex.schema_compliance(recursive=True)
    ]
)
def extract_team_results(team: Team, document: str) -> dict:
    return team.run(document)

financial_team = Team([...])  # header, lines, totals agents
result = extract_team_results(financial_team, "Financial report...")
print(f"Verified team extraction: {result}")
